import axios from 'axios';
const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:4000';
const api = axios.create({ baseURL: API_BASE_URL, headers: { 'Content-Type': 'application/json' } });
api.interceptors.request.use((config) => { const token = localStorage.getItem('token'); if (token) config.headers.Authorization = `Bearer ${token}`; return config; }, (error) => Promise.reject(error));
export const authAPI = { login: async (email, password) => { const response = await api.post('/auth/login', { email, password }); if (response.data.token) { localStorage.setItem('token', response.data.token); localStorage.setItem('user', JSON.stringify(response.data.user)); } return response.data; }, logout: () => { localStorage.removeItem('token'); localStorage.removeItem('user'); }, getCurrentUser: () => { const userStr = localStorage.getItem('user'); return userStr ? JSON.parse(userStr) : null; } };
export const usersAPI = { getAll: async () => { const response = await api.get('/admin/users'); return response.data.map(user => ({ ...user, id: user._id, full_name: user.displayName, status: user.approved ? 'active' : 'pending' })); }, getPending: async () => { const response = await api.get('/admin/users'); return response.data.filter(user => user.approved === false).map(user => ({ ...user, id: user._id, full_name: user.displayName, status: 'pending' })); }, approve: async (id) => { const response = await api.patch(`/admin/users/${id}/approve`); return response.data; }, delete: async (id) => { const response = await api.delete(`/admin/users/${id}`); return response.data; } };
export const roomsAPI = { getAll: async () => { const response = await api.get('/rooms'); return response.data.map(room => ({ ...room, id: room._id })); }, create: async (roomData) => { const response = await api.post('/rooms', roomData); return response.data; }, delete: async (id) => { const response = await api.delete(`/rooms/${id}`); return response.data; } };
export const checklistsAPI = { getAll: async () => { const response = await api.get('/checklists'); return response.data.map(c => ({ ...c, id: c._id })); }, create: async (data) => { const response = await api.post('/checklists', data); return response.data; }, delete: async (id) => { const response = await api.delete(`/checklists/${id}`); return response.data; } };
export const verificationsAPI = { getAll: async () => { const response = await api.get('/verifications'); return response.data.map(v => ({ ...v, id: v._id })); } };
export default api;
